const client = $('Get Client Info').first().json;
const summary = $('Split In Batches').first().json;
const brandColor = client.brand_color || '#6366f1';

const insightIcons = { win: '🏆', watch: '⚠️', next: '🚀' };
const i1Icon = insightIcons[summary.insight_1_type] || '💡';
const i2Icon = insightIcons[summary.insight_2_type] || '💡';
const i3Icon = insightIcons[summary.insight_3_type] || '💡';

const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; color: #1a1a1a; max-width: 600px; margin: 0 auto; padding: 20px; background: #ffffff; }
    .header { border-bottom: 3px solid ${brandColor}; padding-bottom: 16px; margin-bottom: 24px; }
    .header h1 { margin: 0; font-size: 22px; color: #1a1a1a; }
    .header p { color: #666; font-size: 13px; margin: 6px 0 0; }
    .body { font-size: 15px; line-height: 1.7; color: #333; margin-bottom: 24px; }
    .body .hl { color: ${brandColor}; font-weight: 600; }
    .insights-title { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; color: #999; margin-bottom: 12px; }
    .insight { background: #f8f9fa; border-radius: 8px; padding: 14px 18px; margin: 8px 0; border-left: 3px solid ${brandColor}; }
    .insight-title { font-weight: 700; font-size: 14px; margin-bottom: 4px; color: #1a1a1a; }
    .insight-text { font-size: 13px; color: #555; line-height: 1.5; }
    .footer { margin-top: 32px; padding-top: 16px; border-top: 1px solid #eee; font-size: 11px; color: #aaa; text-align: center; }
  </style>
</head>
<body>
  <div class="header">
    <h1>Weekly Report — ${client.company_name || 'Your Company'}</h1>
    <p>${summary.period_start || ''} to ${summary.period_end || ''}</p>
  </div>
  <div class="body">${summary.body_html || '<p>No report body available.</p>'}</div>
  <div class="insights-title">This Week's Insights</div>
  <div class="insight">
    <div class="insight-title">${i1Icon} ${summary.insight_1_title || 'Win'}</div>
    <div class="insight-text">${summary.insight_1_text || ''}</div>
  </div>
  <div class="insight">
    <div class="insight-title">${i2Icon} ${summary.insight_2_title || 'Watch'}</div>
    <div class="insight-text">${summary.insight_2_text || ''}</div>
  </div>
  <div class="insight">
    <div class="insight-title">${i3Icon} ${summary.insight_3_title || 'Next Steps'}</div>
    <div class="insight-text">${summary.insight_3_text || ''}</div>
  </div>
  <div class="footer">
    Generated by ReportFlow
  </div>
</body>
</html>`;

return [{
  json: {
    html,
    to_email: client.contact_email,
    company_name: client.company_name || 'Client',
    period_start: summary.period_start,
    summary_record_id: summary.id
  }
}];
